<?php namespace App\Repositories\Alumni;use App\Repositories\BaseRepository;use App\Models\Alumni\JobPost;use Illuminate\Database\Eloquent\Collection;class JobPostRepository extends BaseRepository{    public function __construct(JobPost $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByCompany(string $company): Collection    {        return $this->findByField('company', $company);    }    public function findByLocation(string $location): Collection    {        return $this->query()->where('location', 'like', "%{$location}%")->get();    }    public function findByEmploymentType(string $type): Collection    {        return $this->findByField('employment_type', $type);    }    public function findByIndustry(string $industry): Collection    {        return $this->findByField('industry', $industry);    }    public function getActivePosts(): Collection    {        return $this->query()->where('is_active', true)->where(function ($q) {                $q->whereNull('closing_date')->orWhere('closing_date', '>=', now());            })->get();    }    public function getRecentPosts(int $limit = 10): Collection    {        return $this->query()->where('is_active', true)->orderBy('posted_date', 'desc')->limit($limit)->get();    }    public function getBySalaryRange(float $min, float $max): Collection    {        return $this->query()->whereBetween('salary_min', [$min, $max])->orWhereBetween('salary_max', [$min, $max])->get();    }    public function searchJobs(string $keyword): Collection    {        return $this->query()->where('title', 'like', "%{$keyword}%")->orWhere('company', 'like', "%{$keyword}%")->orWhere('description', 'like', "%{$keyword}%")->orWhere('requirements', 'like', "%{$keyword}%")->get();    }    public function closePost(int $id): bool    {        return $this->update($id, ['is_active' => false, 'closed_at' => now()]);    }    public function repost(int $id): bool    {        return $this->update($id, ['is_active' => true, 'posted_date' => now(), 'closed_at' => null]);    }}